import { execSync } from "child_process"; import fs from "fs"; import crypto from "crypto";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commit(name,str){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'dep13b',branch:'main',content:Buffer.from(str,'utf8').toString('base64')}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cb.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cb.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000}); }catch(e){ return 'EXC:'+e.message; } }
const code=Buffer.from("",'base64').toString('utf8');
const pcode=Buffer.from("",'base64').toString('utf8').trim();
(async()=>{
  var out={local_md5:'084083d93bb55a94a4c66e0754873963'};
  // deploy #550 v13
  var cur=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  var scope='admin'; try{ scope=JSON.parse(cur).scope||'admin'; }catch(e){}
  fs.writeFileSync('/tmp/p550.json', JSON.stringify({name:'Petshop Susidėjimo Rinkinio Kūrimo Forma v13', code:code, scope:scope, active:true}));
  out.put=exec('curl -sk -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/p550.json "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  var rb=exec('curl -sk -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/550"');
  try{ var j=JSON.parse(rb); out.name=j.name; out.match=(crypto.createHash('md5').update(j.code||'','utf8').digest('hex')===out.local_md5); }catch(e){ out.err=e.message; }
  // probe browse query via #557
  fs.writeFileSync('/tmp/b557.json', JSON.stringify({name:'PSC BROWSECHK', code:pcode, scope:'global', active:true}));
  exec('curl -sk -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/b557.json "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  var r=exec('curl -sk "'+BASE+'/?psc_browsechk=1&k=ps2026"');
  var m=r.match(/(\{.*\})/s); try{ out.browse=JSON.parse(m[0]); }catch(e){ out.browse_raw=(m?m[0]:r).slice(0,200); }
  // deaktyvuojam #557
  exec('curl -sk -X DELETE -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  commit('dep13b_1782983443.json', JSON.stringify(out));
  console.log(JSON.stringify(out));
})();
